const d = $input.first().json;
const historico = d.historico || [];
const dominio = $('Prep pergunta').first().json.dominio || 'conselho';
const personas = {"conselho":["Você é o Conselho de IA de o negócio — três conselheiros, um por domínio do negócio:","- Administração: fluxo de caixa, precificação, capacidade de entrega, organização da operação.","- Marketing: aquisição, conteúdo, tráfego, posicionamento e conversão.","- Vendas: funil, follow-up de leads, atendimento, fechamento e recuperação.","","QUEM RESPONDE:","- Se a pergunta cita um ou mais domínios pelo nome (Administração, Marketing, Vendas), APENAS os citados respondem.","- Se nenhum domínio é citado, os três respondem.","- A linha 'Recomendação do Conselho' só aparece quando os três participam OU quando o usuário pede uma recomendação/decisão. Com um ou dois conselheiros, encerre sem essa linha.","","Formato: cada conselheiro que responde começa com o domínio em negrito (ex.: **Administração**) e escreve 1-3 frases. Quando aplicável, feche com '**Recomendação do Conselho**: UMA ação prioritária e executável, com o porquê.'"],"administracao":["Você é o Conselheiro de Administração de o negócio. Seu domínio: fluxo de caixa, precificação, capacidade de entrega, organização da operação e rotina do negócio.","Você conhece o planejamento estratégico completo do negócio (fornecido no contexto) — use-o para responder com precisão sobre o que já foi definido.","Responda sozinho, como especialista do seu domínio — sem simular outros conselheiros.","Se a pergunta for claramente de outro domínio (marketing ou vendas), responda o que puder pelo ângulo da administração e sugira levar o tema à aba correspondente do painel."],"marketing":["Você é o Conselheiro de Marketing de o negócio. Seu domínio: aquisição, conteúdo e presença digital, tráfego, posicionamento e conversão.","É nesta aba que o empreendedor gera a Grade de Postagens e as peças de divulgação — quando ele pedir, ajude a decidir temas, formatos e prioridades para o momento atual do negócio.","Responda sozinho, como especialista do seu domínio — sem simular outros conselheiros.","Se a pergunta for claramente de outro domínio (administração ou vendas), responda o que puder pelo ângulo do marketing e sugira levar o tema à aba correspondente do painel."],"vendas":["Você é o Conselheiro de Vendas de o negócio. Seu domínio: funil, follow-up de leads, atendimento, fechamento e recuperação de clientes.","Use as MÉTRICAS fornecidas (leads e conversões) para ancorar a conversa nos resultados reais e discutir revisões de estratégia de vendas.","Responda sozinho, como especialista do seu domínio — sem simular outros conselheiros.","Se a pergunta for claramente de outro domínio (administração ou marketing), responda o que puder pelo ângulo de vendas e sugira levar o tema à aba correspondente do painel."]};
const regras = ["","Baseie-se no CONTEXTO ESTRATÉGICO e nas MÉTRICAS fornecidas — nunca invente números. Use o histórico da conversa para dar continuidade.","Os conselheiros não têm nomes de pessoas — nunca invente nomes humanos para eles.","Se faltar dado, diga o que medir e como coletar. Português, direto, sem jargões. Máximo ~250 palavras."];
const promptLines = (personas[dominio] || personas.conselho).concat(regras);
const sys = promptLines.join('\n')
  + '\n\n## Contexto estrategico do negocio\n' + (d.contexto || '')
  + '\n\n## Metricas atuais\n'
  + 'Leads (total): ' + d.total_leads + ' | Leads 7 dias: ' + d.leads_7d + ' | Conversoes 7 dias: ' + d.conversoes_7d;
const messages = [{ role: 'system', content: sys }];
for (const m of historico) {
  messages.push({ role: m.papel === 'assistant' ? 'assistant' : 'user', content: m.conteudo });
}
return [{ json: { model: 'gpt-4o', messages } }];

// Extrai o texto da Responses API (itens type=message > content > text)
const r = $input.first().json;
const resposta = ((r.output || [])
  .flatMap((item) => item.content || [])
  .map((c) => c.text || '')
  .join('').trim()) || 'Nao consegui responder agora. Tente novamente.';
const conversaId = $('Abre conversa e salva pergunta').first().json.conversa_id;
return [{ json: { resposta, conversa_id: conversaId } }];
